BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?actor ?actorName ?prop ?valueName WHERE {
  ?actor rdf:type vocab:actor .
  OPTIONAL { ?actor vocab:NamedElement_name ?actorName }
  ?actor ?prop ?value .
  OPTIONAL { ?value vocab:NamedElement_name ?valueName }
  FILTER(?prop != vocab:NamedElement_name)
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
